const inputItems = $input.all();

if (!inputItems.length) {
  return [
    {
      json: {
        error: true,
        message: "No se han recibido items"
      }
    }
  ];
}

const output = [];

const webhookRaw = $("Webhook").first().json || {};
const webhookData = webhookRaw.body || webhookRaw;

const decryptRaw = $("decrypt credentials").first().json || {};
const decryptData = decryptRaw.body || decryptRaw;

for (const item of inputItems) {

  const row = item.json || {};

  const credentialsRaw = row.credentials || "{}";

  let credentials = {};

  try {
    credentials =
      typeof credentialsRaw === "string"
        ? JSON.parse(credentialsRaw)
        : credentialsRaw;
  } catch (e) {
    credentials = {};
  }

  const body = {
    ...row,
    ...webhookData,
    ...decryptData,
    ...credentials
  };

  const allowRepublish =
    body.allow_republish === true ||
    body.allow_republish === "true";

  const version = Number(
    body.version ||
    body.selected_version ||
    1
  );

  let platforms = [];

  const platformsInput =
    body.platforms ||
    body.selected_platforms ||
    body.publish_platforms ||
    {};

  // Objeto tipo { web:true, linkedin:true }
  if (
    platformsInput &&
    typeof platformsInput === "object" &&
    !Array.isArray(platformsInput)
  ) {

    if (
      platformsInput.web === true ||
      platformsInput.web === "true" ||
      platformsInput.wordpress === true ||
      platformsInput.wordpress === "true"
    ) {
      platforms.push("wordpress");
    }

    if (
      platformsInput.linkedin === true ||
      platformsInput.linkedin === "true"
    ) {
      platforms.push("linkedin");
    }

    if (
      platformsInput.facebook === true ||
      platformsInput.facebook === "true"
    ) {
      platforms.push("facebook");
    }

    if (
      platformsInput.instagram === true ||
      platformsInput.instagram === "true"
    ) {
      platforms.push("instagram");
    }

    if (
      platformsInput.twitter === true ||
      platformsInput.twitter === "true" ||
      platformsInput.x === true ||
      platformsInput.x === "true"
    ) {
      platforms.push("x");
    }
  }

  // Array
  if (Array.isArray(platformsInput)) {
    platforms.push(...platformsInput);
  }

  // String tipo "wordpress,linkedin"
  if (
    typeof platformsInput === "string" &&
    platformsInput.trim()
  ) {
    platforms.push(
      ...platformsInput
        .split(",")
        .map(p => p.trim())
        .filter(Boolean)
    );
  }

  const toggleMap = {
    wordpress: body.wordpress || body.web,
    linkedin: body.linkedin,
    facebook: body.facebook,
    instagram: body.instagram,
    x: body.x || body.twitter
  };

  for (const [platform, value] of Object.entries(toggleMap)) {
    if (
      value === true ||
      value === "true" ||
      value === 1 ||
      value === "1"
    ) {
      platforms.push(platform);
    }
  }

  platforms = [
    ...new Set(
      platforms
        .map(p => String(p).toLowerCase().trim())
        .map(p => p === "web" ? "wordpress" : p)
        .map(p => p === "twitter" ? "x" : p)
        .filter(p =>
          [
            "wordpress",
            "linkedin",
            "facebook",
            "instagram",
            "x"
          ].includes(p)
        )
    )
  ];

  const wpUser = String(
    body.wordpress_user || ""
  ).trim();

  const wpPassword = String(
    body.wordpress_password || ""
  ).replace(/\s+/g, "");

  const wpBasicAuth =
    "Basic " +
    Buffer.from(
      `${wpUser}:${wpPassword}`
    ).toString("base64");

  if (!platforms.length) {

    output.push({
      json: {
        ...body,

        wordpress_user: wpUser,
        wordpress_password: wpPassword,
        wp_basic_auth: wpBasicAuth,

        has_platforms: false,
        status: "no_platform_selected",
        message: "No hay plataformas seleccionadas",

        debug_platformsInput: platformsInput,
        debug_webhook_platforms: webhookData.platforms,
        debug_decrypt_platforms: decryptData.platforms,
        debug_keys: Object.keys(body)
      }
    });

    continue;
  }

  // MUY IMPORTANTE
  delete body.platform;

  for (const currentPlatform of platforms) {

    const publishedIdField = {
      wordpress: "wp_post_id",
      linkedin: "linkedin_post_id",
      facebook: "facebook_post_id",
      instagram: "instagram_post_id",
      x: "x_post_id"
    }[currentPlatform];

    const publishedUrlField = {
      wordpress: "wp_post_url",
      linkedin: "linkedin_post_url",
      facebook: "facebook_post_url",
      instagram: "instagram_post_url",
      x: "x_post_url"
    }[currentPlatform];

    const alreadyPublished =
      Boolean(row[publishedIdField]);

    output.push({
      json: {

        ...body,

        wordpress_user: wpUser,
        wordpress_password: wpPassword,
        wp_basic_auth: wpBasicAuth,

        has_platforms: true,

        allow_republish: allowRepublish,
        selected_version: version,

        already_published: alreadyPublished,

        published_id_field: publishedIdField,
        published_url_field: publishedUrlField,

        published_id:
          row[publishedIdField] || "",

        published_url:
          row[publishedUrlField] || "",

        should_publish: true,

        // FORZADO AL FINAL
        platform: currentPlatform
      }
    });
  }
}

return output;

const crypto = require("crypto");

const input = $json || {};

let body = input.body || input;

if (!body.payload || !body.iv || !body.tag || !body.timestamp || !body.signature) {
  const webhookData = $("Webhook").first().json || {};
  body = webhookData.body || webhookData;
}

const encryptionKeyRaw = $env.WEBHOOK_ENCRYPTION_KEY;
const hmacSecret = $env.WEBHOOK_HMAC_SECRET;

if (!encryptionKeyRaw) {
  throw new Error("Falta WEBHOOK_ENCRYPTION_KEY");
}

if (!hmacSecret) {
  throw new Error("Falta WEBHOOK_HMAC_SECRET");
}

if (!body.payload || !body.iv || !body.tag || !body.timestamp || !body.signature) {
  throw new Error(
    `Faltan campos cifrados obligatorios. Campos disponibles: ${Object.keys(body).join(", ")}`
  );
}

const encryptionKey = Buffer.from(encryptionKeyRaw, "base64");

if (encryptionKey.length !== 32) {
  throw new Error("WEBHOOK_ENCRYPTION_KEY debe tener 32 bytes tras decodificar Base64");
}

const now = Math.floor(Date.now() / 1000);
const timestamp = Number(body.timestamp);

if (!timestamp || Math.abs(now - timestamp) > 300) {
  throw new Error("Petición expirada");
}

const dataToSign = `${body.payload}.${body.iv}.${body.tag}.${body.timestamp}`;

const calculatedSignature = crypto
  .createHmac("sha256", hmacSecret)
  .update(dataToSign)
  .digest("hex");

const receivedSignature = String(body.signature);

if (
  calculatedSignature.length !== receivedSignature.length ||
  !crypto.timingSafeEqual(
    Buffer.from(calculatedSignature, "hex"),
    Buffer.from(receivedSignature, "hex")
  )
) {
  throw new Error("Firma HMAC inválida");
}

const decipher = crypto.createDecipheriv(
  "aes-256-gcm",
  encryptionKey,
  Buffer.from(body.iv, "base64")
);

decipher.setAuthTag(Buffer.from(body.tag, "base64"));

const decrypted = Buffer.concat([
  decipher.update(Buffer.from(body.payload, "base64")),
  decipher.final(),
]);

const parsed = JSON.parse(decrypted.toString("utf8"));

const setData = { ...input };

// Limpiar campos de publicación que no deben arrastrarse
delete setData.platform;
delete setData.published_id_field;
delete setData.published_url_field;
delete setData.published_id;
delete setData.published_url;
delete setData.should_publish;
delete setData.already_published;
delete setData.has_platforms;

const wordpressUser = parsed.wordpress_user || "";
const wordpressPassword = String(parsed.wordpress_password || "").replace(/\s+/g, "");

const wpAuthHeader =
  wordpressUser && wordpressPassword
    ? "Basic " + Buffer.from(`${wordpressUser}:${wordpressPassword}`).toString("base64")
    : null;

return [
  {
    json: {
      ...setData,

      session_id: parsed.session_id || setData.session_id || null,

      wordpress_urlapi: parsed.wordpress_urlapi || null,
      wordpress_user: wordpressUser || null,
      wordpress_password: wordpressPassword || null,
      wp_auth_header: wpAuthHeader,

      linkedin_urloauthredirect: parsed.linkedin_urloauthredirect || null,
      linkedin_clientid: parsed.linkedin_clientid || null,
      linkedin_clientsecret: parsed.linkedin_clientsecret || null,

      x_urloauthredirect: parsed.x_urloauthredirect || null,
      x_clientid: parsed.x_clientid || null,
      x_clientsecret: parsed.x_clientsecret || null
    }
  }
];

const previous = $("Preparador Linkedin").first().json;
const response = $("LinkedIn Posts").first().json;

const headers = response.headers || {};

const linkedinPostId =
  headers["x-restli-id"] ||
  headers["X-RestLi-Id"] ||
  null;

const linkedinPostUrl = linkedinPostId
  ? `https://www.linkedin.com/feed/update/${linkedinPostId}/`
  : null;

return [
  {
    json: {
      ...previous,
      linkedin_success: true,
      linkedin_status: "published",
      linkedin_post_id: linkedinPostId,
      linkedin_post_url: linkedinPostUrl,
      linkedin_api_status_code: response.statusCode || null,
      linkedin_published_at: new Date().toISOString(),
      linkedin_message: "Publicado correctamente en LinkedIn"
    }
  }
];

const previous = $("Preparador Linkedin").first().json;
const response = $("LinkedIn post").first().json;

const linkedinPostId =
  response.urn ||
  response.headers?.["x-restli-id"] ||
  response.headers?.["X-RestLi-Id"] ||
  null;

const linkedinPostUrl = linkedinPostId
  ? `https://www.linkedin.com/feed/update/${linkedinPostId}/`
  : null;

return [
  {
    json: {
      ...previous,
      linkedin_success: true,
      linkedin_status: "published",
      linkedin_post_id: linkedinPostId,
      linkedin_post_url: linkedinPostUrl,
      linkedin_api_status_code: response.statusCode || null,
      linkedin_published_at: new Date().toISOString(),
      linkedin_message: "Publicado correctamente en LinkedIn"
    }
  }
];

