const input = $json || {};

// Datos base
const title = input.title || input.post_title || "";
const contentInstagram =
  input.content_instagram ||
  input.instagram_text ||
  input.content_social ||
  input.content_current ||
  input.content ||
  "";

// Imagen pública ya subida en WP o recibida del WF1
const imageUrl =
  input.image_url ||
  input.featured_image_url ||
  input.media_url ||
  input.source_url ||
  "";

// Credenciales / IDs
const instagramUserId =
  input.instagram_user_id ||
  input.ig_user_id ||
  input.credentials?.instagram_user_id ||
  input.credentials?.ig_user_id ||
  "";

const instagramAccessToken =
  input.instagram_access_token ||
  input.access_token ||
  input.credentials?.instagram_access_token ||
  input.credentials?.access_token ||
  "";

if (!instagramUserId) {
  throw new Error("Falta instagram_user_id / ig_user_id");
}

if (!instagramAccessToken) {
  throw new Error("Falta instagram_access_token");
}

if (!imageUrl) {
  throw new Error("Falta image_url pública para Instagram");
}

const caption = contentInstagram || title;

if (!caption) {
  throw new Error("Falta texto/caption para Instagram");
}

return [
  {
    json: {
      ...input,

      platform: "instagram",

      instagram_user_id: instagramUserId,
      instagram_access_token: instagramAccessToken,

      image_url: imageUrl,
      caption,

      create_media_url: `https://graph.facebook.com/v23.0/${instagramUserId}/media`,
      publish_media_url: `https://graph.facebook.com/v23.0/${instagramUserId}/media_publish`
    }
  }
];

const input = $json || {};

// Texto para Facebook
const contentFacebook =
  input.content_facebook ||
  input.facebook_text ||
  input.content_social ||
  input.content_current ||
  input.content ||
  "";

const title = input.title || input.post_title || "";

// Caption final
const caption = contentFacebook || title;

if (!caption) {
  throw new Error("Falta texto/caption para Facebook");
}

// Imagen pública si existe
const imageUrl =
  input.image_url ||
  input.image_source_url ||
  input.image_current ||
  input.featured_image_url ||
  input.media_url ||
  input.source_url ||
  "";

// Credenciales / IDs
