const facebookPageId =
  input.facebook_page_id ||
  input.page_id ||
  credentials.facebook_page_id ||
  credentials.page_id ||
  "";

const facebookPageAccessToken =
  input.facebook_page_access_token ||
  input.page_access_token ||
  input.facebook_access_token ||
  credentials.facebook_page_access_token ||
  credentials.page_access_token ||
  credentials.facebook_access_token ||
  "";

if (!facebookPageId) {
  throw new Error("Falta facebook_page_id / page_id");
}

if (!facebookPageAccessToken) {
  throw new Error("Falta facebook_page_access_token / page_access_token");
}

return [
  {
    json: {
      ...input,

      platform: "facebook",

      facebook_page_id: facebookPageId,
      facebook_page_access_token: facebookPageAccessToken,

      image_url: imageUrl,
      caption,

      has_public_image_url: Boolean(imageUrl),

      facebook_photos_url: `https://graph.facebook.com/v23.0/${facebookPageId}/photos`,
      facebook_feed_url: `https://graph.facebook.com/v23.0/${facebookPageId}/feed`
    }
  }
];

const input = $json || {};

const cleanLinkedIn = (
  input.content_linkedin ||
  input.linkedin_text ||
  input.content_social ||
  input.content_current ||
  input.content ||
  ""
)
  .replace(/<[^>]*>/g, " ")
  .replace(/&nbsp;/g, " ")
  .replace(/\s+/g, " ")
  .trim()
  .substring(0, 3000);

if (!cleanLinkedIn) {
  throw new Error("Falta contenido para LinkedIn");
}

const credentials = input.credentials || {};

const linkedinAuthor =
  input.linkedin_author ||
  input.linkedin_person_urn ||
  input.linkedin_organization_urn ||
  credentials.linkedin_author ||
  credentials.linkedin_person_urn ||
  credentials.linkedin_organization_urn ||
  urn:li:person:"; // example fallback 

const linkedinImageSource =
  input.linkedin_image_source ||
  input.image_url ||
  input.image_source_url ||
  input.image_current ||
  input.featured_image_url ||
  input.media_url ||
  input.source_url ||
  "";

return [
  {
    json: {
      ...input,

      platform: "linkedin",

      linkedin_author: linkedinAuthor,
      linkedin_image_source: linkedinImageSource,

      linkedin_body: {
        author: linkedinAuthor,
        commentary: cleanLinkedIn,
        visibility: "PUBLIC",
        distribution: {
          feedDistribution: "MAIN_FEED"
        },
        lifecycleState: "PUBLISHED"
      },

      linkedin_success: true,
      content_linkedin_length: cleanLinkedIn.length,
      has_linkedin_image: Boolean(linkedinImageSource)
    }
  }
];

